const fs = require('fs');
const path = require('path');

const SRC_DIR = path.join(__dirname, '..', 'src');
const CORE_DIR = path.join(SRC_DIR, 'core');

function stripImportsExports(content) {
  const lines = content.split('\n');
  const out = [];
  let inMultilineImport = false;

  for (const line of lines) {
    const trimmed = line.trim();

    if (inMultilineImport) {
      if (trimmed.endsWith(';')) inMultilineImport = false;
      continue;
    }

    if (trimmed.startsWith('import ')) {
      if (!trimmed.endsWith(';')) inMultilineImport = true;
      continue;
    }

    if (trimmed.startsWith('export ')) {
      out.push(line.replace(/^\s*export\s+/, ''));
      continue;
    }

    if (/^export\s*\{/.test(trimmed)) {
      continue;
    }

    out.push(line);
  }

  return out.join('\n');
}

const parts = [];

// Order matters: types -> visibility -> extractor -> flattener
parts.push(stripImportsExports(fs.readFileSync(path.join(SRC_DIR, 'types.ts'), 'utf8')));

for (const file of ['visibility.ts', 'extractor.ts', 'flattener.ts']) {
  parts.push(stripImportsExports(fs.readFileSync(path.join(CORE_DIR, file), 'utf8')));
}

const mainLogic = `
function distill(options?: DistillOptions): DistilledNode[] {
  const opts: DistillOptions = {
    maxTextLength: 200,
    includeHidden: false,
    checkObscured: false,
    ...options,
  };

  const PRUNE = new Set([
    'SCRIPT', 'STYLE', 'NOSCRIPT', 'SVG', 'TEMPLATE', 'HEAD', 'META', 'LINK',
  ]);

  interface StackItem {
    el: Element;
    node: DistilledNode;
  }

  const stack: StackItem[] = [];
  const roots: DistilledNode[] = [];

  function walk(root: Node) {
    const tw = document.createTreeWalker(root, NodeFilter.SHOW_ELEMENT, {
      acceptNode(n) {
        if (PRUNE.has((n as Element).tagName)) return NodeFilter.FILTER_REJECT;
        return NodeFilter.FILTER_ACCEPT;
      },
    });

    let node: Node | null;
    while ((node = tw.nextNode())) {
      const el = node as Element;
      if (el.shadowRoot) walk(el.shadowRoot);

      const extracted = extractNode(el, opts);
      if (!extracted) continue;

      while (stack.length > 0 && !stack[stack.length - 1].el.contains(el)) {
        stack.pop();
      }

      if (stack.length > 0) {
        stack[stack.length - 1].node.children.push(extracted);
      } else {
        roots.push(extracted);
      }

      stack.push({ el, node: extracted });
    }
  }

  walk(document.body || document.documentElement);

  const flattened = flattenNodes(roots);
  return pruneEmpty(flattened);
}
`;

parts.push(mainLogic);

// Note: `domDistiller` uses `any` in its signature because the
// `DistillOptions` / `DistilledNode` interfaces are declared inside its body
// (they come from src/types.ts and are bundled in the closure). Hoisting
// the types outside the closure would leak them into the page scope.
const output = `// AUTO-GENERATED by scripts/bundle-injected.js — do not edit manually
// Source: src/core/*.ts
function domDistiller(options?: any): any {
${parts.join('\n')}
return distill(options);
}
`;

fs.writeFileSync(path.join(SRC_DIR, 'injected.ts'), output);
console.log('Generated src/injected.ts');
